import jwt
from cryptography.hazmat.backends import default_backend
from cryptography.hazmat.primitives import serialization, hashes
from cryptography.hazmat.primitives.asymmetric import rsa

def generate_private_key(bits=2048):
    private_key = rsa.generate_private_key(
        public_exponent=65537,
        key_size=bits,
        backend=default_backend()
    )
    return private_key

def generate_public_key(pem_private_key):
    public_key = serialization.load_pem_public_key(
        pem_private_key.public_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PublicFormat.SubjectPublicKeyInfo
        )
    )
    return public_key

def encode_jwt(payload, secret, algorithm='HS256'):
    if algorithm == 'HS256':
        encoded_jwt = jwt.encode(
            payload,
            secret,
            algorithm=algorithm,
            header={'alg': algorithm}
        )
    elif algorithm == 'RS256':
        private_key = generate_private_key()
        encoded_jwt = jwt.encode(
            payload,
            private_key,
            algorithm=algorithm,
            header={'alg': algorithm, 'kid': private_key.public_key().public_bytes(
                encoding=serialization.Encoding.PEM).decode()},
        )
    return encoded_jwt

def decode_jwt(encoded_jwt, secret, public_key=None, algorithm='HS256'):
    if algorithm == 'HS256':
        decoded_payload = jwt.decode(
            encoded_jwt,
            secret,
            algorithms=[algorithm]
        )
    elif algorithm == 'RS256':
        decoded_payload = jwt.decode(
            encoded_jwt,
            public_key,
            algorithms=['RS256']
        )
    return decoded_payload